async function loadIndex() {
  // 优先读取 refresh_index.js 内嵌的数据（双击 file:// 时 fetch 会被阻止）
  if (window.__CARDS_INDEX__) return window.__CARDS_INDEX__;
  try {
    const response = await fetch('./cards-index.json', { cache: 'no-store' });
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    return await response.json();
  } catch (error) {
    console.error(error);
    document.getElementById('resultSummary').textContent = '未找到卡片数据，请先运行 refresh_index.js 刷新索引再重新打开此页。';
    return { generatedAt: null, total: 0, cards: [] };
  }
}

function formatDateTime(value) {
  if (!value) return '--';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString('zh-CN', { hour12: false });
}

function initials(title) {
  const parts = String(title || 'G').split(/[^A-Za-z0-9\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]+/).filter(Boolean);
  return (parts.slice(0, 2).map(part => part[0]).join('') || 'G').toUpperCase();
}

function matchesSearch(card, term) {
  if (!term) return true;
  const target = [card.title, card.fileName, ...(card.tags || [])].join(' ').toLowerCase();
  return target.includes(term.toLowerCase());
}

function sortCards(cards, mode) {
  const list = [...cards];
  switch (mode) {
    case 'updated-asc':
      return list.sort((a, b) => new Date(a.updatedAt) - new Date(b.updatedAt));
    case 'title-asc':
      return list.sort((a, b) => a.title.localeCompare(b.title, 'zh-CN'));
    case 'title-desc':
      return list.sort((a, b) => b.title.localeCompare(a.title, 'zh-CN'));
    case 'updated-desc':
    default:
      return list.sort((a, b) => new Date(b.updatedAt) - new Date(a.updatedAt));
  }
}

function renderCards(cards) {
  const grid = document.getElementById('cardGrid');
  const empty = document.getElementById('emptyState');
  grid.innerHTML = '';

  if (!cards.length) {
    empty.classList.remove('hidden');
    return;
  }
  empty.classList.add('hidden');

  cards.forEach(card => {
    const article = document.createElement('article');
    article.className = 'library-card';
    const iconHtml = card.iconUrl
      ? `<img class="card-icon" src="${card.iconUrl}" alt="${card.title} icon" loading="lazy" onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
        + `<div class="card-badge" style="display:none">${initials(card.title)}</div>`
      : `<div class="card-badge">${initials(card.title)}</div>`;
    article.innerHTML = `
      <div class="card-top">
        <div>
          <h2 class="card-title">${card.title}</h2>
        </div>
        <div class="card-icon-wrap">${iconHtml}</div>
      </div>
      <div class="meta-list">
        <div class="meta-item"><strong>文件：</strong>${card.fileName}</div>
        <div class="meta-item"><strong>类型：</strong>${card.sourceType}</div>
        <div class="meta-item"><strong>更新：</strong>${formatDateTime(card.updatedAt)}</div>
      </div>
      <div class="tags">${(card.tags || []).map(tag => `<span class="tag">${tag}</span>`).join('')}</div>
      <div class="card-actions">
        <a class="open-btn" href="${card.relativePath}" target="_blank" rel="noopener noreferrer">打开卡片</a>
      </div>
    `;
    grid.appendChild(article);
  });
}

function attachEvents(allCards) {
  const searchInput = document.getElementById('searchInput');
  const sortSelect = document.getElementById('sortSelect');
  const filterSelect = document.getElementById('filterSelect');
  const summary = document.getElementById('resultSummary');

  // 动态填充类型筛选选项
  const genres = [...new Set(allCards.map(c => c.sourceType).filter(Boolean))].sort();
  filterSelect.innerHTML = '<option value="all">全部卡片</option>'
    + genres.map(g => `<option value="${g}">${g}</option>`).join('');

  function update() {
    const term = searchInput.value.trim();
    const filter = filterSelect.value;
    const filtered = allCards.filter(card => (filter === 'all' || card.sourceType === filter) && matchesSearch(card, term));
    const sorted = sortCards(filtered, sortSelect.value);
    summary.textContent = `当前显示 ${sorted.length} / ${allCards.length} 张卡片`;
    renderCards(sorted);
  }

  searchInput.addEventListener('input', update);
  sortSelect.addEventListener('change', update);
  filterSelect.addEventListener('change', update);
  update();
}

function attachDialog() {
  const btn = document.getElementById('refreshHintBtn');
  const dialog = document.getElementById('refreshDialog');
  btn.addEventListener('click', () => dialog.showModal());
}

(async function init() {
  const data = await loadIndex();
  document.getElementById('cardCount').textContent = data.total ?? 0;
  document.getElementById('generatedAt').textContent = formatDateTime(data.generatedAt);
  attachEvents(data.cards || []);
  attachDialog();
})();
